package ru.memearena.tournament.application; import org.springframework.dao.*; import org.springframework.http.*; import org.springframework.stereotype.*; import org.springframework.transaction.annotation.*; import ru.memearena.error.*; import ru.memearena.tournament.api.*; import ru.memearena.tournament.domain.*; import ru.memearena.tournament.infrastructure.*; import java.time.*; import java.util.*;
@Service public class TournamentVoteService{ private final TournamentRepository tournaments; private final TournamentMatchRepository matches; private final TournamentVoteRepository votes; private final Clock clock; public TournamentVoteService(TournamentRepository t,TournamentMatchRepository m,TournamentVoteRepository v,Clock c){tournaments=t;matches=m;votes=v;clock=c;} @Transactional public TournamentVoteResponse vote(UUID matchId,UUID userId,UUID selected){TournamentMatch m=matches.findById(matchId).orElseThrow(()->new ApiException(HttpStatus.NOT_FOUND,ErrorCode.TOURNAMENT_MATCH_NOT_FOUND,"Tournament match not found")); Tournament t=tournaments.findById(m.tournamentId).orElseThrow(); if(t.status!=TournamentStatus.ACTIVE) throw new ApiException(HttpStatus.CONFLICT,ErrorCode.TOURNAMENT_NOT_ACTIVE,"Tournament not active"); if(m.status!=TournamentMatchStatus.ACTIVE) throw new ApiException(HttpStatus.CONFLICT,ErrorCode.TOURNAMENT_MATCH_NOT_ACTIVE,"Tournament match not active"); if(!selected.equals(m.leftMemeId)&&!selected.equals(m.rightMemeId)) throw new ApiException(HttpStatus.BAD_REQUEST,ErrorCode.INVALID_TOURNAMENT_SELECTION,"Invalid tournament selection"); try{votes.saveAndFlush(new TournamentVote(UUID.randomUUID(),matchId,userId,selected,Instant.now(clock)));}catch(DataIntegrityViolationException e){throw new ApiException(HttpStatus.CONFLICT,ErrorCode.TOURNAMENT_MATCH_ALREADY_VOTED,"Tournament match already voted");} if(selected.equals(m.leftMemeId))m.leftVotes++; else m.rightVotes++; return new TournamentVoteResponse(matchId,selected,m.leftVotes,m.rightVotes);} }
